import boto3
import os

# WARNING: This is for demo purposes only
# In production, load credentials from environment variables or secret manager
ACCESS_KEY = os.environ.get('AWS_ACCESS_KEY_ID', 'AKIA123EXAMPLE')
SECRET_KEY = os.environ.get('AWS_SECRET_ACCESS_KEY', 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY')
REGION = os.environ.get('AWS_DEFAULT_REGION', 'us-east-1')

def list_s3_files():
    try:
        # Create S3 client
        s3_client = boto3.client(
            's3',
            aws_access_key_id=ACCESS_KEY,
            aws_secret_access_key=SECRET_KEY,
            region_name=REGION
        )
        
        # List all files in the bucket
        response = s3_client.list_objects_v2(Bucket='demo-bucket')
        
        if 'Contents' in response:
            print("Files in demo-bucket:")
            for obj in response['Contents']:
                print(f"  {obj['Key']}")
        else:
            print("Bucket is empty")
            
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    list_s3_files()